func  (this *LbankCore) ParseTransaction(transaction any, optionalArgs ...any) any  {
    //
    // fetchDeposits (private)
    //
    //      {
    //          "insertTime":1649012310000,
    //          "amount":9.00000000000000000000,
    //          "address":"TYASr5UV6HEcXatwdFQfmLVUqQQQMUxHLS",
    //          "networkName":"trc20",
    //          "txId":"081e4e9351dd0274922168da5f2d14ea6c495b1c3b440244f4a6dd9fe196bf2b",
    //          "coin":"usdt",
    //          "status":"2"
    //      }
    //
    //
    // fetchWithdrawals (private)
    //
    //      {
    //          "amount":2.00000000000000000000,
    //          "address":"TBjrW5JHDyPZjFc5nrRMhRWUDaJmhGhmD6",
    //          "fee":1.00000000000000000000,
    //          "networkName":"trc20",
    //          "coid":"usdt",
    //          "transferType":"数字资产提现",
    //          "txId":"47eeee2763ad49b8817524dacfa7d092fb58f8b0ab7e5d25473314df1a793c3d",
    //          "id":1902194,
    //          "applyTime":1649014002000,
    //          "status":"4"
    //      }
    //
    currency := GetArg(optionalArgs, 0, nil)
    _ = currency
    var id any = this.SafeString(transaction, "id")
    var typeVar any = nil
    if IsTrue(IsEqual(id, nil)) {
        typeVar = "deposit"
    } else {
        typeVar = "withdrawal"
    }
    var txid any = this.SafeString(transaction, "txId")
    var timestamp any = this.SafeInteger2(transaction, "insertTime", "applyTime")
    var address any = this.SafeString(transaction, "address")
    var addressFrom any = nil
    var addressTo any = nil
    if IsTrue(IsEqual(typeVar, "deposit")) {
        addressFrom = address
    } else {
        addressTo = address
    }
    var amount any = this.SafeNumber(transaction, "amount")
    var currencyId any = this.SafeString2(transaction, "coin", "coid")
    var code any = this.SafeCurrencyCode(currencyId, currency)
    var status any = this.ParseTransactionStatus(this.SafeString(transaction, "status"), typeVar)
    var fee any = nil
    var feeCost any = this.SafeNumber(transaction, "fee")
    if IsTrue(!IsEqual(feeCost, nil)) {
        fee = map[string]any {
            "cost": feeCost,
            "currency": code,
        }
    }
    return map[string]any {
        "info": transaction,
        "id": id,
        "txid": txid,
        "timestamp": timestamp,
        "datetime": this.Iso8601(timestamp),
        "network": this.NetworkIdToCode(this.SafeString(transaction, "networkName")),
        "address": address,
        "addressTo": addressTo,
        "addressFrom": addressFrom,
        "tag": nil,
        "tagTo": nil,
        "tagFrom": nil,
        "type": typeVar,
        "amount": amount,
        "currency": code,
        "status": status,
        "updated": nil,
        "comment": nil,
        "internal": (IsEqual(status, "transfer")),
        "fee": fee,
    }
}
